//! Integration tests for `operations::metamod`.
//!
//! Each test stages and tears down its own data via `iput` / `imkdir` /
//! `imeta`, then verifies via `imeta ls` that the operation was
//! observable on the server side. Drop guards run regardless of
//! assertion outcome so the tests stay idempotent.

use std::process::Command;

use baton_rs::operations::metamod::{metamod_one, metamod_one_annotated};
use baton_rs::types::{Avu, MetamodInput, MetamodOperation};
use baton_rs::RodsConnection;

/// Drop guard: `irm -r -f` removes data objects and populated
/// collections alike. Errors are swallowed because the test may have
/// failed to stage the path in the first place.
struct IrodsCleanup(String);
impl Drop for IrodsCleanup {
    fn drop(&mut self) {
        let _ = Command::new("irm").args(["-r", "-f", &self.0]).status();
    }
}

fn iput(local: &str, remote: &str) {
    let status = Command::new("iput")
        .args(["-f", local, remote])
        .status()
        .expect("failed to spawn iput");
    assert!(status.success(), "iput {} {} failed", local, remote);
}

fn imkdir(remote: &str) {
    let status = Command::new("imkdir")
        .args(["-p", remote])
        .status()
        .expect("failed to spawn imkdir");
    assert!(status.success(), "imkdir {} failed", remote);
}

/// `imeta add <kind_flag> <path> <attr> <value> [units]`. Used for
/// pre-staging AVUs the rm tests need to remove.
fn imeta_add(kind_flag: &str, path: &str, attr: &str, value: &str, units: Option<&str>) {
    let mut args: Vec<String> = vec![
        "add".to_string(),
        kind_flag.to_string(),
        path.to_string(),
        attr.to_string(),
        value.to_string(),
    ];
    if let Some(u) = units {
        args.push(u.to_string());
    }
    let status = Command::new("imeta")
        .args(&args)
        .status()
        .expect("failed to spawn imeta");
    assert!(status.success(), "imeta add {} {} failed", kind_flag, path);
}

/// Capture `imeta ls <kind_flag> <path>`'s stdout for substring
/// inspection. Returns an empty string on spawn failure.
fn imeta_ls(kind_flag: &str, path: &str) -> String {
    Command::new("imeta")
        .args(["ls", kind_flag, path])
        .output()
        .map(|o| String::from_utf8_lossy(&o.stdout).into_owned())
        .unwrap_or_default()
}

#[test]
fn metamod_add_avu_to_data_object() {
    let local = "/tmp/baton_rs_metamod_add";
    std::fs::write(local, b"metamod add test").expect("write");

    let remote_coll = "/testZone/home/irods";
    let data_object = "baton_rs_metamod_add";
    let remote = format!("{}/{}", remote_coll, data_object);
    iput(local, &remote);
    let _cleanup = IrodsCleanup(remote.clone());

    let mut conn = RodsConnection::connect_from_env().expect("connect_from_env");
    conn.login_from_auth_file().expect("login_from_auth_file");

    let input = MetamodInput {
        collection: remote_coll.to_string(),
        data_object: Some(data_object.to_string()),
        operation: MetamodOperation::Add,
        avus: vec![Avu {
            attribute: "baton_rs_attr".to_string(),
            value: "baton_rs_value".to_string(),
            units: Some("baton_rs_units".to_string()),
        }],
        error: None,
    };

    let output = metamod_one(&mut conn, input).expect("metamod_one");
    assert_eq!(output.error, None);

    let listing = imeta_ls("-d", &remote);
    assert!(
        listing.contains("baton_rs_attr") && listing.contains("baton_rs_value"),
        "expected attr/value in imeta listing, got:\n{}",
        listing
    );
}

#[test]
fn metamod_rm_avu_from_data_object() {
    let local = "/tmp/baton_rs_metamod_rm";
    std::fs::write(local, b"metamod rm test").expect("write");

    let remote_coll = "/testZone/home/irods";
    let data_object = "baton_rs_metamod_rm";
    let remote = format!("{}/{}", remote_coll, data_object);
    iput(local, &remote);
    let _cleanup = IrodsCleanup(remote.clone());

    // Pre-stage the AVU we're about to remove.
    imeta_add("-d", &remote, "rm_target_attr", "rm_target_value", Some("rm_units"));

    let mut conn = RodsConnection::connect_from_env().expect("connect_from_env");
    conn.login_from_auth_file().expect("login_from_auth_file");

    let input = MetamodInput {
        collection: remote_coll.to_string(),
        data_object: Some(data_object.to_string()),
        operation: MetamodOperation::Rm,
        avus: vec![Avu {
            attribute: "rm_target_attr".to_string(),
            value: "rm_target_value".to_string(),
            units: Some("rm_units".to_string()),
        }],
        error: None,
    };

    let output = metamod_one(&mut conn, input).expect("metamod_one");
    assert_eq!(output.error, None);

    let listing = imeta_ls("-d", &remote);
    assert!(
        !listing.contains("rm_target_attr"),
        "AVU should have been removed; imeta listing still shows:\n{}",
        listing,
    );
}

